mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM rooms
    WHERE room_private = TRUE
    AND room_password = #{roomPassword}
)

mapper.update:
UPDATE rooms
SET
    now_users = (
        SELECT COUNT(*)
        FROM room_participants
        WHERE room_no = #{roomNo}
          AND active = TRUE
    ),
    updated_at = NOW()
WHERE room_no = #{roomNo}

mapper.select:
SELECT now_users
FROM rooms
WHERE room_no = #{roomNo}
